1475 static void
1476 removeEntryFromStack(const StackEntry &E, ConstraintInfo &Info,
1477                      Module *ReproducerModule,
1478                      SmallVectorImpl<ReproducerEntry> &ReproducerCondStack,
1479                      SmallVectorImpl<StackEntry> &DFSInStack) {
